  import sailpoint.object.QueryOptions;
  import sailpoint.object.Filter;  
  import sailpoint.object.Bundle;
  import java.util.List;
  import sailpoint.tools.Util;

  List roleLst=new ArrayList();
  List roleNameLst = new ArrayList();
//  System.out.println("000 List of Functional Business Role  datasource ***** " + value);
  QueryOptions queryOptions = new QueryOptions();
  Filter roleFilters = null;
  roleFilters = Filter.and(Filter.in("RoleDivision", value),Filter.or(Filter.eq("type", "it"),(Filter.eq("type", "business"))));	
  queryOptions.addFilter(roleFilters);

  return queryOptions;

