 import sailpoint.object.*;
 import java.util.*;


 List wgs = new ArrayList();

 List props = new ArrayList();
 props.add("name");

 QueryOptions qo = new QueryOptions();
// System.out.println("Member Values "+value);
 qo.addFilter(Filter.eq("workgroups.name", value));
 Iterator entIter = context.search(Identity.class, qo);

 while(entIter.hasNext()){							
 Identity wg = (Identity)entIter.next();
 wgs.add(wg.getName());
 }

 return wgs;


  import sailpoint.object.*;
  import java.util.*;


  List wgs = new ArrayList();
  List props = new ArrayList();
  props.add("name");

  QueryOptions qo = new QueryOptions();
//  System.out.println("Member Values "+value);
  qo.addFilter(Filter.eq("workgroups.name", value));
  Iterator entIter = context.search(Identity.class, qo);

  while(entIter.hasNext()){							
  Identity wg = (Identity)entIter.next();
  wgs.add(wg.getDisplayName());
  }
  return wgs;
